def cut_paper_into_squares(width, height):
    squares = []
    while width > 0 and height > 0:
        if width < height:
            width, height = height, width

        if width == height:
            squares.append(width)
            break

        num_squares_to_cut = width // height
        for _ in range(num_squares_to_cut):
            squares.append(height)

        width = width % height
    return squares
